import { Observable } from 'rxjs';
import { AfterOpr } from './after-opr';
import { BeforeOpr } from './before-opr';
import { FireSQL } from 'firesql';
import 'firesql/rx';
export class SqlStore{
    database:any;
    beforeOpr:BeforeOpr;
    afterOpr:AfterOpr;
    instanceId:string;
    findDBInstance(serviceId?:string){
        if(this.instanceId && serviceId){
            return this.instanceId+'/'+serviceId;
        }
        return this.instanceId;
    }
    inquire2(input:any, pConfig:any, transaction:any) {
        return new Observable<any>(observer => { 
            let includes:any = {includeId: true}
            let fireSQL = new FireSQL(this.database.doc(this.findDBInstance('')), includes);            
            let criteria = this.beforeOpr.intercept("getSql", pConfig, input.body);
            console.log(criteria.value);
            let query = fireSQL.query(criteria.value);
            query.then(documents => {
                observer.next([documents, transaction, criteria]);
                observer.complete();
              }).catch((error) => {
                observer.error(error);
              });                      
        });
    }        
}
